/**
 * Lấy tên User từ token
 */
export function getUserName(): string {
    if (typeof window === 'undefined') return '';

    const token = localStorage.getItem('access_token');
    if (!token) return '';

    const decoded = decodeJwt(token);
    if (!decoded) return '';

    return decoded['http://schemas.xmlsoap.org/ws/2005/05/identity/claims/name'] || decoded.name || decoded.unique_name || decoded.preferred_username || '';
}

/**
 * Lấy ID User từ token 
 */
export function getUserId(): string {
    if (typeof window === 'undefined') return '';

    const token = localStorage.getItem('access_token');
    if (!token) return '';

    const decoded = decodeJwt(token);
    if (!decoded) return '';

    return decoded.sub || decoded.nameidentifier || decoded['http://schemas.xmlsoap.org/ws/2005/05/identity/claims/nameidentifier'] || decoded.Id || '';
}

/**
 * Lấy ID Tenant từ token
 */
export function getTenantId(): string {
    if (typeof window === 'undefined') return '';

    const token = localStorage.getItem('access_token');
    if (!token) return '';

    const decoded = decodeJwt(token);
    if (!decoded) return '';

    return decoded.tenant_id || '';
}
